export class Orgs {
    /**
     * List every workspace the caller is a member of.
     *
     * Returns the active org id (from the JWT) alongside the list so
     * the dashboard's switcher can render in a single round-trip.
     */
    public static listOrgs<ThrowOnError extends boolean = false>(options?: Options<ListOrgsData, ThrowOnError>) {
        return (options?.client ?? client).get<ListOrgsResponses, ListOrgsErrors, ThrowOnError>({
            security: [{ scheme: 'bearer', type: 'http' }],
            url: '/v1/orgs',
            ...options
        });
    }
    
    /**
     * Create a new workspace owned by the caller.
     *
     * Per-user cap of 5 free workspaces (Supabase pattern); paid
     * workspaces don't count against the cap. Sliding-window rate limit
     * of 10 creates per hour per user via Redis (degrades open).
     *
     * Returns `org_count_exceeded` (400) when the free-org cap is hit
     * and `org_rate_limited` (429) when the per-hour limit fires.
     */
    public static createOrg<ThrowOnError extends boolean = false>(options: Options<CreateOrgData, ThrowOnError>) {
        return (options.client ?? client).post<CreateOrgResponses, CreateOrgErrors, ThrowOnError>({
            security: [{ scheme: 'bearer', type: 'http' }],
            url: '/v1/orgs',
            ...options,
            headers: {
                'Content-Type': 'application/json',
                ...options.headers
            }
        });
    }
    
    /**
     * Soft-delete a workspace. Requires the Owner role. Blocked when
     * the workspace is the caller's last owned workspace (would leave
     * the user orgless and unable to authenticate) — returns
     * `cannot_delete_last_org` (400) in that case.
     */
    public static deleteOrg<ThrowOnError extends boolean = false>(options: Options<DeleteOrgData, ThrowOnError>) {
        return (options.client ?? client).delete<DeleteOrgResponses, DeleteOrgErrors, ThrowOnError>({
            security: [{ scheme: 'bearer', type: 'http' }],
            url: '/v1/orgs/{org_id}',
            ...options
        });
    }
    
    /**
     * Rename a workspace. Requires the Admin role.
     */
    public static renameOrg<ThrowOnError extends boolean = false>(options: Options<RenameOrgData, ThrowOnError>) {
        return (options.client ?? client).put<RenameOrgResponses, RenameOrgErrors, ThrowOnError>({
            security: [{ scheme: 'bearer', type: 'http' }],
            url: '/v1/orgs/{org_id}',
            ...options,
            headers: {
                'Content-Type': 'application/json',
                ...options.headers
            }
        });
    }
    
    /**
     * List a workspace's invitations, newest first. Forward-only
     * cursor pagination on `(created_at DESC, id DESC)`.
     *
     * Filter by status with `?status=pending` (single) or
     * `?status=pending,accepted` (multiple). Unknown statuses return
     * 400 (`invalid_query_parameter`) rather than silently empty pages.
     */
    public static listInvitations<ThrowOnError extends boolean = false>(options: Options<ListInvitationsData, ThrowOnError>) {
        return (options.client ?? client).get<ListInvitationsResponses, ListInvitationsErrors, ThrowOnError>({
            security: [{ scheme: 'bearer', type: 'http' }],
            url: '/v1/orgs/{org_id}/invitations',
            ...options
        });
    }
    
    /**
     * Send an invitation to join a workspace. Requires the Admin role.
     *
     * Side effects: creates a WorkOS organization on first use, sends
     * the invitation email via WorkOS, and persists a local pending
     * invitation row. All three are atomic from the caller's
     * perspective — the WorkOS round-trip is wrapped by a Postgres
     * transaction with an advisory lock that serializes concurrent
     * sends from the same workspace.
     *
     * Per-org rate limit (Free: 5/hr, Team: 20/hr, Enterprise: none) and
     * seat-cap enforcement (members + pending invites <= plan limit).
     * Returns `conflict_already_invited` (409) if a pending invitation
     * already exists for the email.
     */
    public static sendInvitation<ThrowOnError extends boolean = false>(options: Options<SendInvitationData, ThrowOnError>) {
        return (options.client ?? client).post<SendInvitationResponses, SendInvitationErrors, ThrowOnError>({
            security: [{ scheme: 'bearer', type: 'http' }],
            url: '/v1/orgs/{org_id}/invitations',
            ...options,
            headers: {
                'Content-Type': 'application/json',
                ...options.headers
            }
        });
    }
    
    /**
     * Resend an invitation. Requires the Admin role.
     *
     * Implemented as revoke + new send: WorkOS' own resend endpoint
     * doesn't reliably refresh `expires_at`, and customers expect a
     * fresh expiration on resend. The original row is transitioned to
     * `"revoked"` and a new pending row is inserted, both audited.
     */
    public static resendInvitation<ThrowOnError extends boolean = false>(options: Options<ResendInvitationData, ThrowOnError>) {
        return (options.client ?? client).post<ResendInvitationResponses, ResendInvitationErrors, ThrowOnError>({
            security: [{ scheme: 'bearer', type: 'http' }],
            url: '/v1/orgs/{org_id}/invitations/{invitation_id}/resend',
            ...options
        });
    }
    
    /**
     * Revoke a pending invitation. Requires the Admin role.
     *
     * WorkOS-first ordering: the upstream invitation is revoked before
     * the local row, so a partial failure leaves the email link dead
     * (the safe direction). Only `"pending"` invitations can be
     * revoked; accepted/revoked/expired return
     * `invitation_invalid_state` (409).
     */
    public static revokeInvitation<ThrowOnError extends boolean = false>(options: Options<RevokeInvitationData, ThrowOnError>) {
        return (options.client ?? client).post<RevokeInvitationResponses, RevokeInvitationErrors, ThrowOnError>({
            security: [{ scheme: 'bearer', type: 'http' }],
            url: '/v1/orgs/{org_id}/invitations/{invitation_id}/revoke',
            ...options
        });
    }
    
    /**
     * List every member of a workspace. Any member of the workspace
     * (regardless of role) can view the roster.
     */
    public static listMembers<ThrowOnError extends boolean = false>(options: Options<ListMembersData, ThrowOnError>) {
        return (options.client ?? client).get<ListMembersResponses, ListMembersErrors, ThrowOnError>({
            security: [{ scheme: 'bearer', type: 'http' }],
            url: '/v1/orgs/{org_id}/members',
            ...options
        });
    }
    
    /**
     * Remove a member from a workspace. Requires the Admin role.
     *
     * Cannot remove an owner — the DELETE statement is scoped with
     * `role != 'owner'`, so attempting to remove an owner returns 404
     * the same as a non-existent membership. To demote an owner first,
     * use `PUT /v1/orgs/{org_id}/members/{member_id}/role`.
     */
    public static removeMember<ThrowOnError extends boolean = false>(options: Options<RemoveMemberData, ThrowOnError>) {
        return (options.client ?? client).delete<RemoveMemberResponses, RemoveMemberErrors, ThrowOnError>({
            security: [{ scheme: 'bearer', type: 'http' }],
            url: '/v1/orgs/{org_id}/members/{member_id}',
            ...options
        });
    }
    
    /**
     * Update a member's role. Requires the Admin role.
     *
     * The mutation is linearizable: the implementation locks every
     * owner row of the workspace before evaluating the
     * "is this the last owner" check inside a single CTE statement,
     * so two concurrent demotions of two distinct owners cannot both
     * succeed. Demoting the last remaining owner returns a 422
     * validation error (`last_owner`).
     */
    public static updateMemberRole<ThrowOnError extends boolean = false>(options: Options<UpdateMemberRoleData, ThrowOnError>) {
        return (options.client ?? client).put<UpdateMemberRoleResponses, UpdateMemberRoleErrors, ThrowOnError>({
            security: [{ scheme: 'bearer', type: 'http' }],
            url: '/v1/orgs/{org_id}/members/{member_id}/role',
            ...options,
            headers: {
                'Content-Type': 'application/json',
                ...options.headers
            }
        });
    }
}

